// src/views/user/MyProfile/composables/useFormValidation.js
import { validationRules } from '../constants/rules'

export function useFormValidation() {
  const validateForm = async (formRef, formData) => {
    if (!formRef) return false
    try {
      // 只验证有值的字段
      const filledFields = Object.entries(formData).reduce((acc, [key, value]) => {
        if (value) {
          acc[key] = validationRules.basic[key]
        }
        return acc
      }, {})

      // 如果没有需要验证的字段，直接返回 true
      if (Object.keys(filledFields).length === 0) {
        return true
      }

      // 设置动态验证规则
      formRef.clearValidate()
      formRef.setRules(filledFields)

      // 执行验证
      await formRef.validate()
      return true
    } catch (error) {
      console.error('表单验证失败:', error)
      return false
    }
  }

  return {
    rules: validationRules.basic,
    validateForm
  }
}
